import Link from 'next/link'
import { Button } from './ui/button'
import { Link2 } from 'lucide-react'

export default function LinkButton({ linkHref, linkTarget, children, handleOnClick }) {
  return (
    <Link className='' href={`/${linkHref}`} target={linkTarget}>
      <Button
        variant='link'
        onClick={() => {
          // sessionStorage.setItem('school', JSON.stringify(school))
          handleOnClick()
        }}
      >
        <Link2 />
        {children}
      </Button>
    </Link>
  )
}
